export async function enrichCompany(domain: string): Promise<EnrichedCompany | null> {
  const res = await fetch(`https://company.clearbit.com/v2/companies/find?domain=${domain}`, {
    headers: { Authorization: `Bearer ${process.env.CLEARBIT_API_KEY}` },
  });
  if (res.status === 404) return null;
  if (!res.ok) {
    throw new Error(`Clearbit lookup failed: ${res.status}`);
  }
  const data = await res.json();
  return {
    name: data.name,
    industry: data.category?.industry ?? null,
    employees: data.metrics?.employees ?? null,
  };
}
